import{c as a,Q as r,j as t,m as o}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"The Decoder — 2026-05-13","description":"","frontmatter":{"title":"The Decoder — 2026-05-13","date":"2026-05-13T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-13-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-13-the-decoder.md","lastUpdated":1779894392000}'),i={name:"research/ai-news/2026-05/2026-05-13-the-decoder.md"};function s(l,e,n,d,c,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="🔓-the-decoder-—-2026-05-13" tabindex="-1">🔓 The Decoder — 2026-05-13 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-13" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-13&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="android-gets-ai-agents-that-book-trips-fill-forms-and-clean-up-your-texts" tabindex="-1"><a href="https://the-decoder.com/gemini-intelligence-makes-autofill-chrome-and-gboard-on-android-smarter/" target="_blank" rel="noreferrer">Android gets AI agents that book trips, fill forms, and clean up your texts</a> <a class="header-anchor" href="#android-gets-ai-agents-that-book-trips-fill-forms-and-clean-up-your-texts" aria-label="Permalink to &quot;[Android gets AI agents that book trips, fill forms, and clean up your texts](https://the-decoder.com/gemini-intelligence-makes-autofill-chrome-and-gboard-on-android-smarter/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-12</em></p><p>With Gemini Intelligence, Google is introducing new AI features for Android that automate multi-step tasks, summarize web content, fill out forms, and turn spoken thoughts into polished text messages.</p><p>The article <a href="https://the-decoder.com/gemini-intelligence-makes-autofill-chrome-and-gboard-on-android-smarter/" target="_blank" rel="noreferrer">Android gets AI agents that book trips, fill forms, and clean up your texts</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="anthropic-expands-legal-ai-offerings-with-new-claude-cowork-plugins" tabindex="-1"><a href="https://the-decoder.com/anthropic-expands-legal-ai-offerings-with-new-cowork-plugins/" target="_blank" rel="noreferrer">Anthropic expands legal AI offerings with new Claude Cowork plugins</a> <a class="header-anchor" href="#anthropic-expands-legal-ai-offerings-with-new-claude-cowork-plugins" aria-label="Permalink to &quot;[Anthropic expands legal AI offerings with new Claude Cowork plugins](https://the-decoder.com/anthropic-expands-legal-ai-offerings-with-new-cowork-plugins/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-12</em></p><p>Anthropic launches twelve new Claude plugins for legal work covering contract law, employment law, and litigation, while connecting the chatbot to services like Thomson Reuters&#39; CoCounsel Legal and Harvey. According to Anthropic&#39;s chief legal officer, lawyers use Claude more than almost any other profession.</p><p>The article <a href="https://the-decoder.com/anthropic-expands-legal-ai-offerings-with-new-cowork-plugins/" target="_blank" rel="noreferrer">Anthropic expands legal AI offerings with new Claude Cowork plugins</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="google-says-it-stopped-a-mass-cyberattack-after-ai-was-used-to-discover-a-zero-day-exploit" tabindex="-1"><a href="https://the-decoder.com/google-says-it-stopped-a-mass-cyberattack-after-ai-was-used-to-discover-a-zero-day-exploit/" target="_blank" rel="noreferrer">Google says it stopped a mass cyberattack after AI was used to discover a zero-day exploit</a> <a class="header-anchor" href="#google-says-it-stopped-a-mass-cyberattack-after-ai-was-used-to-discover-a-zero-day-exploit" aria-label="Permalink to &quot;[Google says it stopped a mass cyberattack after AI was used to discover a zero-day exploit](https://the-decoder.com/google-says-it-stopped-a-mass-cyberattack-after-ai-was-used-to-discover-a-zero-day-exploit/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-12</em></p><p>Google&#39;s Threat Intelligence Group has identified the first known case of an attacker using AI to discover and weaponize a zero-day vulnerability. Google says it stopped the planned mass attack. State-backed actors from China, North Korea, and Russia are also using AI to find vulnerabilities and disguise malware code.</p><p>The article <a href="https://the-decoder.com/google-says-it-stopped-a-mass-cyberattack-after-ai-was-used-to-discover-a-zero-day-exploit/" target="_blank" rel="noreferrer">Google says it stopped a mass cyberattack after AI was used to discover a zero-day exploit</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="alphabet-s-isomorphic-labs-raises-2-1-billion-to-scale-ai-drug-discovery-toward-clinical-trials" tabindex="-1"><a href="https://the-decoder.com/alphabets-isomorphic-labs-raises-2-1-billion-to-scale-ai-drug-discovery-toward-clinical-trials/" target="_blank" rel="noreferrer">Alphabet&#39;s Isomorphic Labs raises $2.1 billion to scale AI drug discovery toward clinical trials</a> <a class="header-anchor" href="#alphabet-s-isomorphic-labs-raises-2-1-billion-to-scale-ai-drug-discovery-toward-clinical-trials" aria-label="Permalink to &quot;[Alphabet&#39;s Isomorphic Labs raises $2.1 billion to scale AI drug discovery toward clinical trials](https://the-decoder.com/alphabets-isomorphic-labs-raises-2-1-billion-to-scale-ai-drug-discovery-toward-clinical-trials/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-12</em></p><p>Isomorphic Labs, the AI drug research company led by DeepMind co-founder Demis Hassabis, has closed a $2.1 billion Series B round led by Thrive Capital. The funding will go toward expanding its in-house platform IsoDDE and advancing drug candidates toward clinical trials.</p><p>The article <a href="https://the-decoder.com/alphabets-isomorphic-labs-raises-2-1-billion-to-scale-ai-drug-discovery-toward-clinical-trials/" target="_blank" rel="noreferrer">Alphabet&#39;s Isomorphic Labs raises $2.1 billion to scale AI drug discovery toward clinical trials</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="microsoft-ousts-its-israel-chief-following-reports-that-azure-quietly-powered-military-ai-targeting-in-gaza" tabindex="-1"><a href="https://the-decoder.com/microsoft-ousts-its-israel-chief-following-reports-that-azure-quietly-powered-military-ai-targeting-in-gaza/" target="_blank" rel="noreferrer">Microsoft ousts its Israel chief following reports that Azure quietly powered military AI targeting in Gaza</a> <a class="header-anchor" href="#microsoft-ousts-its-israel-chief-following-reports-that-azure-quietly-powered-military-ai-targeting-in-gaza" aria-label="Permalink to &quot;[Microsoft ousts its Israel chief following reports that Azure quietly powered military AI targeting in Gaza](https://the-decoder.com/microsoft-ousts-its-israel-chief-following-reports-that-azure-quietly-powered-military-ai-targeting-in-gaza/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-12</em></p><p>Microsoft Israel&#39;s top executive is out after an internal investigation into the unit&#39;s work with Israel&#39;s defense ministry. Reporting over the past years points to what&#39;s likely at the center of it all: cloud infrastructure, mass surveillance, and AI-powered target selection in Gaza.</p><p>The article <a href="https://the-decoder.com/microsoft-ousts-its-israel-chief-following-reports-that-azure-quietly-powered-military-ai-targeting-in-gaza/" target="_blank" rel="noreferrer">Microsoft ousts its Israel chief following reports that Azure quietly powered military AI targeting in Gaza</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const f=a(i,[["render",s]]);export{g as __pageData,f as default};
